import React from "react";
import css from "./Registration.module.css"
import { Button, Input } from "antd";

const Registration = () => {
    return (
        <div className={css.wrapper} >
            <div className={css.InputBlock}>
                <Input placeholder="Enter nickname" className={css.NickName}></Input>
                <Input placeholder="Enter the chat name" className={css.ChatName}></Input>
                <Button>Войти</Button>
            </div>
        </div>
    )
}

export default Registration;
